patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index 4ed4c36e21e0..1f4a583ecd94 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -1526,7 +1526,71 @@ Instruction *InstCombinerImpl::visitUDiv(BinaryOperator &I) {
     return replaceInstUsesWith(
         I, Builder.CreateLShr(Op0, Res, I.getName(), I.isExact()));
   }
-
+  // (X / C) << N + (X % C) --> X + (X / C) * ((1 << N) - C)
+  // This optimization recognizes the pattern where a division and remainder
+  // are combined, which can be simplified using the identity:
+  //   X = (X / C) * C + (X % C)
+  // Therefore:
+  //   (X / C) * 2^N + (X % C) = (X / C) * 2^N + X - (X / C) * C
+  //                          = X + (X / C) * (2^N - C)
+  Value *ShlUser = nullptr;
+  ConstantInt *ShiftAmt = nullptr;
+  BinaryOperator *URem = nullptr;
+  BinaryOperator *CombineOp = nullptr;
+  
+  if (I.hasOneUse() && match(I.getOperand(1), m_APInt(C1))) {
+    // Check if the udiv result is used by exactly one shift instruction
+    User *SingleUser = *I.user_begin();
+    if (match(SingleUser, m_Shl(m_Specific(&I), m_ConstantInt(ShiftAmt)))) {
+      // Check if the shift has exactly one use
+      if (SingleUser->hasOneUse()) {
+        // Check if there's a urem with the same operands
+        for (User *U : Op0->users()) {
+          if (auto *Rem = dyn_cast<BinaryOperator>(U)) {
+            if (Rem->getOpcode() == Instruction::URem &&
+                Rem->getOperand(0) == Op0 &&
+                Rem->getOperand(1) == Op1 &&
+                Rem->hasOneUse()) {
+              // Check if the urem and shift are combined by or/add
+              // Check if the urem and shift are combined by or/add
+              Instruction *CombineUser = dyn_cast<Instruction>(*SingleUser->user_begin());
+              if (CombineUser &&
+                  (CombineUser->getOpcode() == Instruction::Or ||
+                   CombineUser->getOpcode() == Instruction::Add) &&
+                  ((CombineUser->getOperand(0) == SingleUser &&
+                    CombineUser->getOperand(1) == Rem) ||
+                   (CombineUser->getOperand(1) == SingleUser &&
+                    CombineUser->getOperand(0) == Rem))) {
+                ShlUser = SingleUser;
+                URem = Rem;
+                CombineOp = cast<BinaryOperator>(CombineUser);
+                break;
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+  
+  
+  if (ShlUser && URem && CombineOp) {
+    unsigned BitWidth = cast<IntegerType>(Ty)->getBitWidth();
+    APInt ShiftVal = APInt::getOneBitSet(BitWidth, ShiftAmt->getZExtValue());
+    APInt MulConst = ShiftVal - *C1;
+    
+    if (MulConst.isStrictlyPositive()) {
+      // Create new instructions after CombineOp
+      IRBuilder<> Builder(CombineOp->getNextNode());
+      Value *Mul = Builder.CreateMul(&I, ConstantInt::get(Ty, MulConst), "",
+                                     true, false);
+      Value *Add = Builder.CreateAdd(Mul, Op0);
+      CombineOp->replaceAllUsesWith(Add);
+      eraseInstFromFunction(*CombineOp);
+      return &I;
+    }
+  }
+  return nullptr;
   return nullptr;
 }

